/**
 * 会话结束时的兜底备份脚本（Stop Hook 调用）
 * 会在对话结束后自动保存一份原始 JSONL 到 Obsidian 作为最后防线
 */
const fs = require('fs');
const path = require('path');

const OBSIDIAN_DIR = 'E:/道友的宝贝/道友的宝贝/对话归档/CC';
const PROJECTS_DIR = path.join(process.env.HOME || process.env.USERPROFILE || 'C:/Users/Administrator', '.claude', 'projects');

if (!fs.existsSync(OBSIDIAN_DIR)) {
  console.error(`[backup-session] Obsidian dir not found: ${OBSIDIAN_DIR}`);
  process.exit(0); // non-critical, exit cleanly
}

// Find all project session dirs, look for the Desktop project
const projectDirs = fs.readdirSync(PROJECTS_DIR).filter(d =>
  d.includes('Desktop') && fs.statSync(path.join(PROJECTS_DIR, d)).isDirectory()
);

if (projectDirs.length === 0) {
  console.error('[backup-session] No Desktop project dir found');
  process.exit(0);
}

// Take the first match
const projectDir = path.join(PROJECTS_DIR, projectDirs[0]);
const files = fs.readdirSync(projectDir)
  .filter(f => f.endsWith('.jsonl'))
  .map(f => ({
    name: f,
    mtime: fs.statSync(path.join(projectDir, f)).mtime,
    fullPath: path.join(projectDir, f)
  }))
  .sort((a, b) => b.mtime - a.mtime); // newest first

if (files.length === 0) {
  console.error('[backup-session] No JSONL files found');
  process.exit(0);
}

// Copy the latest session JSONL as raw backup
const latest = files[0];
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const timeStr = now.toISOString().split('T')[1].slice(0, 5).replace(':', '-');
const backupName = `${dateStr}_会话备份_${timeStr}.jsonl.txt`;
const destPath = path.join(OBSIDIAN_DIR, backupName);

fs.copyFileSync(latest.fullPath, destPath);
console.log(`[backup-session] ✅ Backup saved: ${backupName} (${(fs.statSync(destPath).size / 1024).toFixed(0)} KB)`);

