/**
 * 对话归档 — Stop Hook 兜底脚本
 * 会话结束时自动运行，确保数据不丢
 * 规则：对话轮次 < 10 不归档
 */
const fs = require('fs');
const path = require('path');

const HOME = process.env.HOME || process.env.USERPROFILE || 'C:/Users/Administrator';
const OBSIDIAN_DIR = 'E:/道友的宝贝/道友的宝贝/对话归档/CC';
const REGISTRY_FILE = 'D:/ClaudeWorkspace/.session_registry.json';
const SESSION_NOTE = 'D:/ClaudeWorkspace/当前会话笔记.md';

if (!fs.existsSync(OBSIDIAN_DIR)) {
  fs.mkdirSync(OBSIDIAN_DIR, { recursive: true });
}

// === Read session registry ===
let registry = { sessionTurns: 0, obsidianNote: '' };
if (fs.existsSync(REGISTRY_FILE)) {
  try {
    registry = JSON.parse(fs.readFileSync(REGISTRY_FILE, 'utf-8'));
  } catch (e) { /* ignore */ }
}

const turnCount = registry.sessionTurns || 0;

// === Archive session note if >= 10 turns ===
if (fs.existsSync(SESSION_NOTE)) {
  const stat = fs.statSync(SESSION_NOTE);
  const content = fs.readFileSync(SESSION_NOTE, 'utf-8');

  if (turnCount >= 10 && content.trim().length > 0) {
    // Use registered note path or generate one
    let destPath;
    if (registry.obsidianNotePath && fs.existsSync(path.dirname(registry.obsidianNotePath))) {
      destPath = registry.obsidianNotePath;
    } else {
      // Fallback: generate from note mtime
      const dateStr = stat.mtime.toISOString().split('T')[0];
      const topic = registry.conversationTopic || '会话记录';
      const safeTopic = topic.replace(/[<>:"/\\|?*]/g, '_');
      destPath = path.join(OBSIDIAN_DIR, `${dateStr}_${safeTopic}.md`);
    }

    fs.copyFileSync(SESSION_NOTE, destPath);
    console.log(`[backup-session] ✅ 已同步到 Obsidian: ${path.basename(destPath)} (${turnCount}轮)`);
  } else {
    console.log(`[backup-session] ⏭ 跳过归档：仅 ${turnCount} 轮对话（需 ≥10 轮）`);
  }
}

// === Raw JSONL backup (always, regardless of turn count) ===
const PROJECTS_DIR = path.join(HOME, '.claude', 'projects');
if (fs.existsSync(PROJECTS_DIR)) {
  const projectDirs = fs.readdirSync(PROJECTS_DIR).filter(d =>
    d.includes('Desktop') && fs.statSync(path.join(PROJECTS_DIR, d)).isDirectory()
  );
  if (projectDirs.length > 0) {
    const projectDir = path.join(PROJECTS_DIR, projectDirs[0]);
    const files = fs.readdirSync(projectDir)
      .filter(f => f.endsWith('.jsonl'))
      .map(f => ({
        name: f, mtime: fs.statSync(path.join(projectDir, f)).mtime,
        fullPath: path.join(projectDir, f)
      }))
      .sort((a, b) => b.mtime - a.mtime);
    if (files.length > 0) {
      const latest = files[0];
      const now = new Date();
      const dateStr = now.toISOString().split('T')[0];
      const timeStr = now.toISOString().split('T')[1].slice(0, 5).replace(':', '-');
      const backupName = `${dateStr}_原始数据_${timeStr}.jsonl.txt`;
      fs.copyFileSync(latest.fullPath, path.join(OBSIDIAN_DIR, backupName));
    }
  }
}

console.log('[backup-session] ✅ 完成');

