/**
 * 对话归档 — Stop Hook 兜底脚本
 * 会话结束时自动运行，确保数据不丢
 */
const fs = require('fs');
const path = require('path');

const HOME = process.env.HOME || process.env.USERPROFILE || 'C:/Users/Administrator';
const OBSIDIAN_DIR = 'E:/道友的宝贝/道友的宝贝/对话归档/CC';
const PROJECTS_DIR = path.join(HOME, '.claude', 'projects');
const SESSION_NOTE = 'D:/ClaudeWorkspace/当前会话笔记.md';

// Ensure Obsidian dir exists
if (!fs.existsSync(OBSIDIAN_DIR)) {
  fs.mkdirSync(OBSIDIAN_DIR, { recursive: true });
}

// === Step 1: Archive session note if it exists ===
if (fs.existsSync(SESSION_NOTE)) {
  const content = fs.readFileSync(SESSION_NOTE, 'utf-8');
  const noteMtime = fs.statSync(SESSION_NOTE).mtime;

  // Extract title from note (first heading or use date)
  const titleMatch = content.match(/^#\s+(.+)/m);
  const topic = titleMatch ? titleMatch[1].trim().slice(0, 60) : '会话记录';
  const dateStr = noteMtime.toISOString().split('T')[0];
  const safeTopic = topic.replace(/[<>:"/\\|?*]/g, '_');
  const archivePath = path.join(OBSIDIAN_DIR, `${dateStr}_${safeTopic}.md`);

  // Avoid overwriting - add suffix if exists
  let finalPath = archivePath;
  let suffix = 1;
  while (fs.existsSync(finalPath)) {
    const ext = path.extname(archivePath);
    const base = archivePath.slice(0, -ext.length);
    finalPath = `${base}_${suffix}${ext}`;
    suffix++;
  }

  fs.copyFileSync(SESSION_NOTE, finalPath);
  console.log(`[backup-session] ✅ 会话笔记已归档: ${path.basename(finalPath)}`);

  // Clear session note for next session
  fs.writeFileSync(SESSION_NOTE, '');
}

// === Step 2: Backup raw JSONL if exists ===
const projectDirs = fs.readdirSync(PROJECTS_DIR).filter(d =>
  d.includes('Desktop') && fs.statSync(path.join(PROJECTS_DIR, d)).isDirectory()
);

if (projectDirs.length > 0) {
  const projectDir = path.join(PROJECTS_DIR, projectDirs[0]);
  const files = fs.readdirSync(projectDir)
    .filter(f => f.endsWith('.jsonl'))
    .map(f => ({
      name: f,
      mtime: fs.statSync(path.join(projectDir, f)).mtime,
      fullPath: path.join(projectDir, f)
    }))
    .sort((a, b) => b.mtime - a.mtime);

  if (files.length > 0) {
    const latest = files[0];
    const now = new Date();
    const dateStr = now.toISOString().split('T')[0];
    const timeStr = now.toISOString().split('T')[1].slice(0, 5).replace(':', '-');
    const backupName = `${dateStr}_原始会话_${timeStr}.jsonl.txt`;
    const destPath = path.join(OBSIDIAN_DIR, backupName);
    fs.copyFileSync(latest.fullPath, destPath);
    console.log(`[backup-session] ✅ 原始数据已备份: ${backupName} (${(fs.statSync(destPath).size / 1024).toFixed(0)} KB)`);
  }
}

console.log('[backup-session] ✅ 对话归档兜底完成');

